import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterLink } from '@angular/router';
import { AdminSetting } from '../../core/models';

interface ServiceGroup {
  service: string;
  title: string;
  blurb: string;
  settings: AdminSetting[];
  configured: boolean;
}

/**
 * LearnLoop admin settings (instructor). Lists each provisioned backing service
 * (postgresql, minio, llm) with a configured/unconfigured badge and a
 * per-service credential form. Mock data in a signal<AdminSetting[]>;
 * service_agent wires ApiService.getSettings()/updateSettings().
 */
@Component({
  selector: 'app-admin-settings',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './admin-settings.component.html',
  styleUrl: './admin-settings.component.css',
})
export class AdminSettingsComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly saved = signal<string | null>(null);

  readonly settings = signal<AdminSetting[]>([
    { key: 'DATABASE_URL', service: 'postgresql', label: 'Connection URL', value: 'postgres://…@db:5432/learnloop', configured: true },
    { key: 'MINIO_ENDPOINT', service: 'minio', label: 'Endpoint', value: '', configured: false },
    { key: 'MINIO_ACCESS_KEY', service: 'minio', label: 'Access key', value: '', configured: false },
    { key: 'MINIO_SECRET_KEY', service: 'minio', label: 'Secret key', value: '', configured: false },
    { key: 'LLM_API_BASE', service: 'llm', label: 'API base URL', value: '', configured: false },
    { key: 'LLM_API_KEY', service: 'llm', label: 'API key', value: '', configured: false },
  ]);

  // Editable draft values keyed by setting key.
  drafts: Record<string, string> = {};

  private readonly serviceMeta: Record<string, { title: string; blurb: string }> = {
    postgresql: { title: 'PostgreSQL', blurb: 'Primary application database.' },
    minio: { title: 'MinIO Object Storage', blurb: 'S3-compatible object storage for course media uploads.' },
    llm: { title: 'LLM Provider', blurb: 'Language model credentials for AI-assisted authoring.' },
  };

  readonly groups = computed<ServiceGroup[]>(() => {
    const byService = new Map<string, AdminSetting[]>();
    for (const s of this.settings()) {
      if (!byService.has(s.service)) byService.set(s.service, []);
      byService.get(s.service)!.push(s);
    }
    return [...byService.entries()].map(([service, settings]) => ({
      service,
      title: this.serviceMeta[service]?.title ?? service,
      blurb: this.serviceMeta[service]?.blurb ?? '',
      settings,
      configured: settings.every((s) => s.configured),
    }));
  });

  ngOnInit(): void {
    for (const s of this.settings()) this.drafts[s.key] = '';
    // service_agent: this.api.getSettings().subscribe(s => this.settings.set(s));
  }

  saveGroup(group: ServiceGroup): void {
    this.saved.set(null);
    this.error.set(null);
    // Mark each setting configured if a draft value was entered.
    this.settings.update((list) =>
      list.map((s) => {
        if (s.service !== group.service) return s;
        const draft = this.drafts[s.key];
        return draft ? { ...s, value: draft, configured: true } : s;
      }),
    );
    for (const s of group.settings) this.drafts[s.key] = '';
    this.saved.set(group.title);
    // service_agent: this.api.updateSettings(payload).subscribe(...)
  }
}
